mapper.select:
select a.*,
       c.course_name,
       u.real_name as student_name
from attendance_record a
         left join course_info c on a.course_id = c.id
         left join sys_user u on a.student_id = u.id


        and a.schedule_id = #{scheduleId}


        and a.student_id = #{studentId}


        and a.teacher_id = #{teacherId}


order by a.id desc

mapper.update:
update attendance_record
attendance_date = #{attendanceDate}, attendance_status = #{attendanceStatus}, remark = #{remark},
where id = #{id}
